//! Golden CDR tests for cross-language validation.
//!
//! Each test reads a `.cdr` file generated by Python's pycdr2 library
//! (`scripts/generate_cdr_testdata.py`) and validates three phases:
//!
//! 1. **Decode** — deserialize the golden bytes and verify every field.
//! 2. **Construct** — build the same message from scratch and assert
//!    byte-identical CDR output.
//! 3. **Modify** — mutate a field and verify the roundtrip.
//!
//! If any phase fails, the Rust and Python CDR implementations disagree
//! on layout, alignment, or field encoding.

// Golden test values are exact wire-format constants from Python pycdr2, not approximations.
#![allow(clippy::approx_constant)]

use std::path::PathBuf;

use edgefirst_schemas::builtin_interfaces::{Duration, Time};
use edgefirst_schemas::cdr::{decode_fixed, encode_fixed};
use edgefirst_schemas::edgefirst_msgs::{self, Date, DetectBoxView, MaskView};
use edgefirst_schemas::foxglove_msgs::{
    self, FoxgloveCircleAnnotations, FoxgloveColor, FoxglovePoint2, FoxglovePointAnnotationView,
    FoxgloveTextAnnotationView,
};
use edgefirst_schemas::geometry_msgs::{
    self, Accel, Inertia, Point, Point32, Pose, Pose2D, Quaternion, Transform, Twist, Vector3,
};
use edgefirst_schemas::rosgraph_msgs::Clock;
use edgefirst_schemas::sensor_msgs::{self, NavSatStatus, PointFieldView, RegionOfInterest};
use edgefirst_schemas::std_msgs::{self, ColorRGBA};

// ── Helpers ────────────────────────────────────────────────────────────────

fn read_golden(namespace: &str, type_name: &str) -> Vec<u8> {
    let path = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("testdata/cdr")
        .join(namespace)
        .join(format!("{type_name}.cdr"));
    std::fs::read(&path).unwrap_or_else(|e| panic!("read {}: {e}", path.display()))
}

/// Shared timestamp used across all golden files.
const STAMP: Time = Time {
    sec: 1234567890,
    nanosec: 123456789,
};
const FRAME_ID: &str = "test_frame";

// ── builtin_interfaces ─────────────────────────────────────────────────────

#[test]
fn golden_builtin_interfaces_time() {
    let golden = read_golden("builtin_interfaces", "Time");
    // Phase 1: decode
    let t: Time = decode_fixed(&golden).unwrap();
    assert_eq!(t.sec, 1234567890);
    assert_eq!(t.nanosec, 123456789);
    // Phase 2: construct
    let built = Time::new(1234567890, 123456789);
    assert_eq!(encode_fixed(&built).unwrap(), golden);
    // Phase 3: modify
    let mut m = t;
    m.sec = 42;
    let re: Time = decode_fixed(&encode_fixed(&m).unwrap()).unwrap();
    assert_eq!(re.sec, 42);
    assert_eq!(re.nanosec, t.nanosec);
}

#[test]
fn golden_builtin_interfaces_duration() {
    let golden = read_golden("builtin_interfaces", "Duration");
    let d: Duration = decode_fixed(&golden).unwrap();
    assert_eq!(d.sec, 60);
    assert_eq!(d.nanosec, 500000000);
    let built = Duration::new(60, 500000000);
    assert_eq!(encode_fixed(&built).unwrap(), golden);
    let mut m = d;
    m.sec = 120;
    let re: Duration = decode_fixed(&encode_fixed(&m).unwrap()).unwrap();
    assert_eq!(re.sec, 120);
    assert_eq!(re.nanosec, d.nanosec);
}

