#[test]
fn golden_geometry_msgs_vector3() {
    let golden = read_golden("geometry_msgs", "Vector3");
    let v: Vector3 = decode_fixed(&golden).unwrap();
    assert_eq!(v.x, 1.5);
    assert_eq!(v.y, -2.5);
    assert_eq!(v.z, 3.0);
    let built = Vector3 {
        x: 1.5,
        y: -2.5,
        z: 3.0,
    };
    assert_eq!(encode_fixed(&built).unwrap(), golden);
    let mut m = v;
    m.x = 42.0;
    let re: Vector3 = decode_fixed(&encode_fixed(&m).unwrap()).unwrap();
    assert_eq!(re.x, 42.0);
    assert_eq!(re.y, v.y);
    assert_eq!(re.z, v.z);
}

#[test]
fn golden_geometry_msgs_point() {
    let golden = read_golden("geometry_msgs", "Point");
    let p: Point = decode_fixed(&golden).unwrap();
    assert_eq!(p.x, 1.5);
    assert_eq!(p.y, -2.5);
    assert_eq!(p.z, 3.0);
    let built = Point {
        x: 1.5,
        y: -2.5,
        z: 3.0,
    };
    assert_eq!(encode_fixed(&built).unwrap(), golden);
    let mut m = p;
    m.z = 99.0;
    let re: Point = decode_fixed(&encode_fixed(&m).unwrap()).unwrap();
    assert_eq!(re.z, 99.0);
    assert_eq!(re.x, p.x);
}

