#[test]
fn golden_std_msgs_header() {
    let golden = read_golden("std_msgs", "Header");
    // Phase 1: decode
    let view = std_msgs::Header::from_cdr(&golden[..]).unwrap();
    assert_eq!(view.stamp(), STAMP);
    assert_eq!(view.frame_id(), FRAME_ID);
    // Phase 2: construct
    let built = std_msgs::Header::new(STAMP, FRAME_ID).unwrap();
    assert_eq!(built.to_cdr(), golden);
    // Phase 3: modify stamp
    let mut h = std_msgs::Header::from_cdr(golden.clone()).unwrap();
    h.set_stamp(Time::new(42, 0)).unwrap();
    assert_eq!(h.stamp(), Time::new(42, 0));
    assert_eq!(h.frame_id(), FRAME_ID);
}

