#[test]
fn golden_edgefirst_msgs_date() {
    let golden = read_golden("edgefirst_msgs", "Date");
    let d: Date = decode_fixed(&golden).unwrap();
    assert_eq!(d.year, 2025);
    assert_eq!(d.month, 6);
    assert_eq!(d.day, 15);
    let built = Date {
        year: 2025,
        month: 6,
        day: 15,
    };
    assert_eq!(encode_fixed(&built).unwrap(), golden);
    let mut m = d;
    m.year = 2030;
    let re: Date = decode_fixed(&encode_fixed(&m).unwrap()).unwrap();
    assert_eq!(re.year, 2030);
    assert_eq!(re.month, d.month);
}

