fn golden_edgefirst_msgs_radar_cube() {
    let golden = read_golden("edgefirst_msgs", "RadarCube");
    let view = edgefirst_msgs::RadarCube::from_cdr(&golden[..]).unwrap();
    assert_eq!(view.stamp(), STAMP);
    assert_eq!(view.frame_id(), FRAME_ID);
    assert_eq!(view.timestamp(), 1234567890123456);
    assert_eq!(view.layout(), &[6, 1, 5, 2]);
    assert_eq!(view.shape(), &[2, 4, 2, 2]);
    assert_eq!(view.scales(), &[1.0f32, 2.5, 1.0, 0.5]);
    let total = 2 * 4 * 2 * 2;
    assert_eq!(view.cube().len(), total);
    let expected_cube: Vec<i16> = (0..total as i16).map(|i| i * 100).collect();
    assert_eq!(view.cube(), expected_cube.as_slice());
    assert!(!view.is_complex());
    // Phase 2
    let built = edgefirst_msgs::RadarCube::new(
        STAMP,
        FRAME_ID,
        1234567890123456,
        &[6, 1, 5, 2],
        &[2, 4, 2, 2],
        &[1.0, 2.5, 1.0, 0.5],
        &expected_cube,
        false,
    )
    .unwrap();
    assert_eq!(built.to_cdr(), golden);
    // Phase 3
    let rc2 = edgefirst_msgs::RadarCube::new(
        STAMP,
        FRAME_ID,
        1234567890123456,
        &[6, 1, 5, 2],
        &[2, 4, 2, 2],
        &[1.0, 2.5, 1.0, 0.5],
        &expected_cube,
        true, // complex = true
    )
    .unwrap();
    assert_ne!(rc2.to_cdr(), golden);
}

