#[test]
fn golden_foxglove_msgs_compressed_video() {
    let golden = read_golden("foxglove_msgs", "CompressedVideo");
    let view = foxglove_msgs::FoxgloveCompressedVideo::from_cdr(&golden[..]).unwrap();
    assert_eq!(view.stamp(), STAMP);
    assert_eq!(view.frame_id(), "camera");
    let expected_data: Vec<u8> = (0..32).collect();
    assert_eq!(view.data(), expected_data.as_slice());
    assert_eq!(view.format(), "h264");
    // Phase 2
    let built =
        foxglove_msgs::FoxgloveCompressedVideo::new(STAMP, "camera", &expected_data, "h264")
            .unwrap();
    assert_eq!(built.to_cdr(), golden);
    // Phase 3: modify stamp
    let mut cv = foxglove_msgs::FoxgloveCompressedVideo::from_cdr(golden.clone()).unwrap();
    cv.set_stamp(Time::new(42, 0)).unwrap();
    assert_eq!(cv.stamp(), Time::new(42, 0));
    assert_eq!(cv.format(), "h264"); // unchanged
}

