#[test]
fn golden_foxglove_msgs_point_annotation() {
    let golden = read_golden("foxglove_msgs", "PointsAnnotation");
    let view = foxglove_msgs::FoxglovePointAnnotation::from_cdr(&golden[..]).unwrap();
    assert_eq!(view.timestamp(), STAMP);
    assert_eq!(view.type_(), 1); // POINTS
    let pts = view.points();
    assert_eq!(pts.len(), 3);
    assert_eq!(pts[0].x, 0.0);
    assert_eq!(pts[0].y, 0.0);
    assert_eq!(pts[1].x, 10.0);
    assert_eq!(pts[1].y, 20.0);
    assert_eq!(pts[2].x, 20.0);
    assert_eq!(pts[2].y, 40.0);
    let oc = view.outline_color();
    assert_eq!(oc.g, 1.0);
    assert_eq!(view.outline_colors().len(), 0);
    let fc = view.fill_color();
    assert_eq!(fc.b, 1.0);
    assert_eq!(fc.a, 0.5);
    assert_eq!(view.thickness(), 3.0);
    // Phase 2
    let pts_arr = [
        FoxglovePoint2 { x: 0.0, y: 0.0 },
        FoxglovePoint2 { x: 10.0, y: 20.0 },
        FoxglovePoint2 { x: 20.0, y: 40.0 },
    ];
    let built = foxglove_msgs::FoxglovePointAnnotation::new(
        STAMP,
        1,
        &pts_arr,
        FoxgloveColor {
            r: 0.0,
            g: 1.0,
            b: 0.0,
            a: 1.0,
        },
        &[],
        FoxgloveColor {
            r: 0.0,
            g: 0.0,
            b: 1.0,
            a: 0.5,
        },
        3.0,
    )
    .unwrap();
    assert_eq!(built.to_cdr(), golden);
    // Phase 3
    let pa2 = foxglove_msgs::FoxglovePointAnnotation::new(
        STAMP,
        2,
        &pts_arr, // LINE_LOOP
        FoxgloveColor {
            r: 0.0,
            g: 1.0,
            b: 0.0,
            a: 1.0,
        },
        &[],
        FoxgloveColor {
            r: 0.0,
            g: 0.0,
            b: 1.0,
            a: 0.5,
        },
        3.0,
    )
    .unwrap();
    assert_ne!(pa2.to_cdr(), golden);
}

#[test]
fn golden_foxglove_msgs_image_annotation() {
    let golden = read_golden("foxglove_msgs", "ImageAnnotations");
    let view = foxglove_msgs::FoxgloveImageAnnotation::from_cdr(&golden[..]).unwrap();
    // Phase 1: verify sub-elements
    let circles = view.circles();
    assert_eq!(circles.len(), 1);
    assert_eq!(circles[0].diameter, 50.0);
    assert_eq!(circles[0].position.x, 100.0);
    let points = view.points();
    assert_eq!(points.len(), 1);
    assert_eq!(points[0].type_, 1);
    assert_eq!(points[0].points.len(), 3);
    let texts = view.texts();
    assert_eq!(texts.len(), 1);
    assert_eq!(texts[0].text, "hello");
    assert_eq!(texts[0].font_size, 14.0);
    // Phase 2
    let circle = FoxgloveCircleAnnotations {
        timestamp: STAMP,
        position: FoxglovePoint2 { x: 100.0, y: 200.0 },
        diameter: 50.0,
        thickness: 2.0,
        fill_color: FoxgloveColor {
            r: 1.0,
            g: 0.0,
            b: 0.0,
            a: 0.5,
        },
        outline_color: FoxgloveColor {
            r: 0.0,
            g: 1.0,
            b: 0.0,
            a: 1.0,
        },
    };
    let pts_arr = vec![
        FoxglovePoint2 { x: 0.0, y: 0.0 },
        FoxglovePoint2 { x: 10.0, y: 20.0 },
        FoxglovePoint2 { x: 20.0, y: 40.0 },
    ];
    let pts_ann = FoxglovePointAnnotationView {
        timestamp: STAMP,
        type_: 1,
        points: pts_arr,
        outline_color: FoxgloveColor {
            r: 0.0,
            g: 1.0,
            b: 0.0,
            a: 1.0,
        },
        outline_colors: vec![],
        fill_color: FoxgloveColor {
            r: 0.0,
            g: 0.0,
            b: 1.0,
            a: 0.5,
        },
        thickness: 3.0,
    };
    let text_ann = FoxgloveTextAnnotationView {
        timestamp: STAMP,
        position: FoxglovePoint2 { x: 50.0, y: 100.0 },
        text: "hello",
        font_size: 14.0,
        text_color: FoxgloveColor {
            r: 1.0,
            g: 1.0,
            b: 1.0,
            a: 1.0,
        },
        background_color: FoxgloveColor {
            r: 0.0,
            g: 0.0,
            b: 0.0,
            a: 0.5,
        },
    };
    let built =
        foxglove_msgs::FoxgloveImageAnnotation::new(&[circle], &[pts_ann], &[text_ann]).unwrap();
    assert_eq!(built.to_cdr(), golden);
    // Phase 3
    let built2 = foxglove_msgs::FoxgloveImageAnnotation::new(
        &[],
        &[],
        &[], // empty
    )
    .unwrap();
    assert_ne!(built2.to_cdr(), golden);
}

// ── rosgraph_msgs ─────────────────────────────────────────────────────────

#[test]
fn golden_rosgraph_msgs_clock() {
    let golden = read_golden("rosgraph_msgs", "Clock");
    let c: Clock = decode_fixed(&golden).unwrap();
    assert_eq!(c.clock.sec, 1234567890);
    assert_eq!(c.clock.nanosec, 123456789);
    let built = Clock { clock: STAMP };
    assert_eq!(encode_fixed(&built).unwrap(), golden);
    let mut m = c;
    m.clock.sec = 0;
    let re: Clock = decode_fixed(&encode_fixed(&m).unwrap()).unwrap();
    assert_eq!(re.clock.sec, 0);
    assert_eq!(re.clock.nanosec, c.clock.nanosec);
}
